const key = $json.sessionKey;
const stored = $getWorkflowStaticData('global');
const history = stored[key] ? JSON.parse(stored[key]) : [];

return [{
  json: {
    chatId: $json.chatId,
    question: $json.question,
    sessionKey: $json.sessionKey,
    modelProvider: $json.modelProvider,
    history: history
  }
}];

const { chatId, question, sessionKey, modelProvider, history } = $json;

const isHebrew = /[\u05d0-\u05ea]/.test(question);
const langInstruction = isHebrew
  ? 'IMPORTANT: The user is writing in Hebrew. You MUST respond entirely in Hebrew. Do not use English at all.'
  : "Respond in the same language as the user's message.";

const messages = [
  {
    role: 'system',
    content: `You are Alex's AI assistant. Answer questions clearly and accurately. Provide concise, useful information. Structure responses when it helps readability. Avoid unnecessary filler or overly casual language. ${langInstruction}`
  },
  ...history,
  {
    role: 'user',
    content: question
  }
];

return [{
  json: {
    chatId,
    question,
    sessionKey,
    modelProvider,
    messages
  }
}];

const prev = $('Build Messages').first().json;

// Handle response from either LM Studio (HTTP) or OpenAI node
let answer = '';
if ($json.choices) {
  // LM Studio HTTP response
  answer = ($json.choices?.[0]?.message?.content || '').trim();
} else {
  // OpenAI node response
  answer = ($json.message?.content || $json.text || '').trim();
}

const key = prev.sessionKey;
const stored = $getWorkflowStaticData('global');
let history = stored[key] ? JSON.parse(stored[key]) : [];

history.push({ role: 'user', content: prev.question });
history.push({ role: 'assistant', content: answer });

if (history.length > 20) history = history.slice(-20);

stored[key] = JSON.stringify(history);

return [{
  json: {
    chatId: prev.chatId,
    answer: answer
  }
}];

